using namespace std;

const int N = 1e4 + 10;
int s[N];

struct DSU {
    vector<int> parent;
    vector<int> size;
    DSU(int n) { 
        parent = vector<int> (n + 1);
        size = vector<int> (n + 1);
        for(int i = 1; i <= n; i++) {
            parent[i] = i; 
            size[i] = 1;
        }
    }
    int find_parent(int v) {
        if(parent[v] == v) 
            return v;
        return parent[v] = find_parent(parent[v]);
    }
    void merge_set(int a, int b) {
        a = find_parent(a);
        b = find_parent(b);

        // Merge on the score of the dishes
        if(s[b] > s[a]) {    
            parent[a] = b;
        }
        else if(s[a] > s[b]) {
            parent[b] = a;
        }
    }
    bool same_set(int a, int b) {
        if(find_parent(a) == find_parent(b)) {
            return true;
        }
        return false;
    }
};


int main() {
    int t; cin >> t;
    while(t--) {
        int n, q; 
        cin >> n;
        DSU d(n);

        for(int i = 1; i <= n; i++) {
            cin >> s[i];
        }   

        cin >> q;
        for(int i = 1; i <= q; i++) {
            int type; cin >> type;
            if(type == 0) {
                int x, y; cin >> x >> y;
                if(d.same_set(x, y)) {
