#include <stdio.h>
#include <stdlib.h>
#define N 10010 // Define N as a preprocessor macro

int s[N];

// Define the DSU structure
typedef struct {
    int *parent;
    int *size;
    int n;
} DSU;

// Function to initialize DSU with n elements
void dsu_init(DSU *dsu, int n) {
    dsu->n = n;
    dsu->parent = (int *)malloc((n + 1) * sizeof(int));
    dsu->size = (int *)malloc((n + 1) * sizeof(int));
    for(int i = 1; i <= n; i++) {
        dsu->parent[i] = i;
        dsu->size[i] = 1;
    }
}

// Function to find the topmost parent of an element
int find_parent(DSU *dsu, int v) {
    if(dsu->parent[v] == v) 
        return v;
    return dsu->parent[v] = find_parent(dsu, dsu->parent[v]);
}

// Function to merge two sets based on the scores of the dishes
void merge_set(DSU *dsu, int a, int b) {
    a = find_parent(dsu, a);
    b = find_parent(dsu, b);

    if(s[b] > s[a]) {    
        dsu->parent[a] = b;
    } else if(s[a] > s[b]) {
        dsu->parent[b] = a;
    }
}

// Function to check if two elements are in the same set
int same_set(DSU *dsu, int a, int b) {
    return find_parent(dsu, a) == find_parent(dsu, b);
}

// Function to free allocated memory
void dsu_free(DSU *dsu) {
    free(dsu->parent);
    free(dsu->size);
}

int main() {
    int t;
    scanf("%d", &t);

    while(t--) {
        int n, q;
        scanf("%d", &n);

        DSU dsu;
        dsu_init(&dsu, n);

        for(int i = 1; i <= n; i++) {
            scanf("%d", &s[i]);
        }

        scanf("%d", &q);
        for(int i = 1; i <= q; i++) {
            int type;
            scanf("%d", &type);
            if(type == 0) {
                int x, y;
                scanf("%d %d", &x, &y);
                if(same_set(&dsu, x, y)) {
                    printf("Invalid query!\n");
                } else {
                    merge_set(&dsu, x, y);
                }
            } else {
                int x;
                scanf("%d", &x);
                printf("%d\n", find_parent(&dsu, x));
            }
        }

        // Clean up
        dsu_free(&dsu);
    }

    return 0;
}

